function binImg = fImgNxNBin(img,binN,aLgc)%% image n x n binning (even number arrays only)%% binImg: binned image%% img: input image% binN: bin number N% aLgc: average logic (1 for average, 0 for sum)%% Written by Kei Nakamura% % 2020/8/7 ver.1: Created %% main bodymodI = mod(size(img),binN);img = img(1:end-modI(1),1:end-modI(2)); % shape imageszI = size(img)/binN;binImg = zeros(szI);for ii=1:binN    for jj=1:binN        binImg = binImg + img(ii:binN:end,jj:binN:end);    endendif aLgc==1    binImg = binImg/binN^2;end
